export function normalizeOfferPremiseData(premise: ResponseOfferPremiseData): PremiseData {
	return {
		externalId: premise.external_id,
		id: premise.id,
		name: premise.name,
		description: premise.description,
		logo: premise.logo,
		emails: premise.emails,
		phones: premise.phones,
		locality: premise.locality && {
			address: premise.locality.address,
			addressId: premise.locality.address_id,
			citypart: premise.locality.citypart,
			countryId: premise.locality.country_id,
			district: premise.locality.district,
			districtId: premise.locality.district_id,
			districtSeoName: premise.locality.district_seo_name,
			entityId: premise.locality.entity_id,
			entityType: premise.locality.entity_type,
			gpsLat: premise.locality.gps_lat,
			gpsLon: premise.locality.gps_lon,
			housenumber: premise.locality.housenumber,
			municipality: premise.locality.municipality,
			municipalityId: premise.locality.municipality_id,
			municipalitySeoName: premise.locality.municipality_seo_name,
			quarter: premise.locality.quarter,
			quarterId: premise.locality.quarter_id,
			quarterSeoName: getSeoName(premise.locality.quarter),
			region: premise.locality.region,
			regionId: premise.locality.region_id,
			regionSeoName: premise.locality.region_seo_name,
			source: premise.locality.source,
			street: premise.locality.street,
			streetId: premise.locality.street_id,
			streetnumber: premise.locality.streetnumber,
			ward: premise.locality.ward,
			wardId: premise.locality.ward_id,
			wardSeoName: getSeoName(premise.locality.ward),
			zip: premise.locality.zip,
		},
		openingHours: premise.opening_hours && {
			openingTimeAdditionalInfo: premise.opening_hours.opening_time_additional_info,
			openingTimeDescription: premise.opening_hours.opening_time_description,
			openingTimeHolidayInfo: premise.opening_hours.opening_time_holiday_info,
			openingTimeSt: premise.opening_hours.opening_time_st,
			openingTimeVisible: premise.opening_hours.opening_time_visible,
		},
		reviews: premise.reviews,
		subject: premise.subject,
		seoName: premise.seo_name,
		urlDetailFirmy: premise.url_detail_firmy,
		useAdvertLocality: premise.use_advert_locality,
		web: premise.web,
		oldId: premise.old_id,
		isPremise: true,
	};
}
