import { type LocalityData, normalizeLocality, type ResponseLocalityData } from 'service/locality/model';
import { normalizePublicUserData, type PublicUserData, type ResponsePublicUserData } from 'service/user/model';
import { normalizeOfferImage, type OfferImage, type ResponseOfferImage } from 'service/image/model';
import { normalizeOfferVideo, type OfferVideo, type ResponseOfferVideo } from 'service/video/model';
import { normalizeOfferPremiseData, type PremiseData, type ResponseOfferPremiseData } from 'service/premise/model';
import {
	normalizeOfferCategoryData,
	type OfferCategoryData,
	type ResponseOfferCategoryData,
} from 'service/category/model';

export type ResponseOfferBuyerProtectionRule = {
	price: number;
	valid_from_date: string;
	valid_to_date: string;
};

export type BuyerOfferProtectionRule = {
	price: number;
	validFromDate: string | null;
	validToDate: string | null;
};

export type OfferStatus = 'active' | 'inactive' | 'deleted' | 'disabled';

export type ApiOfferStatistics = {
	detail_view: number | null | undefined;
};

export type OfferStatistics = {
	detailView: number | null | undefined;
};

export type OfferLocation = {
	id: number;
	locality: LocalityData;
	main: boolean;
};

export type ApprovalAdmin = 'unchecked' | 'approved' | 'rejected';

export type ApiOfferData = {
	approval_admin: undefined | ApprovalAdmin;
	buyer_protection?: boolean;
	buyer_protection_rule?: ResponseOfferBuyerProtectionRule;
	category: ResponseOfferCategoryData;
	custom_id: undefined | number;
	create_date: string;
	deactivation_reason: undefined | null | string;
	deal_type: undefined | string;
	description: null | string;
	dont_show_phone: undefined | boolean;
	edit_date: `${number}-${number}-${number}T${number}:${number}:${number}`;
	id: number;
	images: undefined | ResponseOfferImage[];
	is_advert_mirroring: undefined | boolean;
	is_reserved: undefined | boolean;
	locality: ResponseLocalityData;
	localities:
		| undefined
		| {
				id: number;
				locality: ResponseLocalityData;
				main: boolean;
		  }[];

	manufacturer_cb: undefined | { name: string; seo_name: string; value: number };
	mirroring_id: undefined | null | number;
	model_cb: undefined | { name: string; seo_name: string; value: number };
	name: string;
	old_id: null | number;
	other_localities: undefined | ResponseLocalityData[];
	other_localities_count: undefined | number;
	phone: string;
	premise: undefined | null | ResponseOfferPremiseData;
	preferred_offer: undefined | boolean;
	price: number;
	price_by_agreement: boolean;
	price_original: undefined | number;
	recommendation_data: undefined | string;
	sauto_more_seo_url: undefined | string;
	seo_name: string;
	sold: undefined | WhereSold;
	sorting_date: string;
	source: string;
	status: OfferStatus;
	statistics: undefined | ApiOfferStatistics;
	topped: boolean;
	user: undefined | ResponsePublicUserData;
	valid_to: undefined | string;
	videos: undefined | ResponseOfferVideo[];
	videos_total_count: number;
};

export type DraftApiOfferData = ApiOfferData & {
	category: null | ResponseOfferCategoryData;
};

export type OfferData = {
	approvalAdmin: undefined | ApprovalAdmin;
	buyerProtection?: boolean;
	buyerProtectionRule?: BuyerOfferProtectionRule;
	category: OfferCategoryData;
	customId?: undefined | number;
	createDate: string;
	deactivationReason: undefined | null | string;
	dealType: undefined | string;
	description: null | string;
	dontShowPhone: undefined | boolean;
	editDate: string;
	id: number;
	images: undefined | OfferImage[];
	isOfferMirroring: undefined | boolean;
	isReserved: undefined | boolean;
	locality: undefined | LocalityData;
	localities: undefined | OfferLocation[];
	manufacturerCb: undefined | { name: string; seoName: string; value: number };
	mirroringId: undefined | null | number;
	modelCb: undefined | { name: string; seoName: string; value: number };
	name: string;
	oldId: null | number;
	otherLocalities: undefined | LocalityData[];
	otherLocalitiesCount: undefined | number;
	phone: string;
	premise: undefined | null | PremiseData;
	preferredOffer: undefined | boolean;
	price: number;
	priceByAgreement: boolean;
	priceOriginal: undefined | number;
	recommendationData: undefined | string;
	sautoMoreSeoUrl: undefined | string;
	seoName: string;
	sold: undefined | WhereSold;
	sortingDate: string;
	source: string;
	statistics?: undefined | OfferStatistics;
	status: OfferStatus;
	topped: boolean;
	user: undefined | PublicUserData;
	validTo: undefined | string;
	videos: undefined | OfferVideo[];
	videosTotalCount: number;
	loadedOnPageNumber?: number;
};

export type DraftOfferData = Omit<Partial<OfferData>, 'category'> & {
	termsOfUse?: boolean;
	email?: string;
	category: OfferCategoryData | null | undefined;
};

export function normalizeDraftOfferData(offer: DraftApiOfferData, isLabMode?: boolean): DraftOfferData {
	const locality = offer.locality && normalizeLocality(offer.locality);
	const otherLocalities = offer.other_localities?.map((locality) => normalizeLocality(locality));

	return {
		approvalAdmin: offer.approval_admin,
		buyerProtection: isLabMode ? offer.buyer_protection : undefined,
		buyerProtectionRule: isLabMode ? normalizeOfferBuyerProtectionRule(offer.buyer_protection_rule) : undefined,
		category: offer.category ? normalizeOfferCategoryData(offer.category) : null,
		createDate: offer.create_date,
		customId: offer.custom_id,
		deactivationReason: offer.deactivation_reason,
		dealType: offer.deal_type,
		description: offer.description,
		dontShowPhone: offer.dont_show_phone,
		editDate: offer.edit_date,
		id: offer.id,
		images: offer.images?.map((image) => normalizeOfferImage(image)),
		isOfferMirroring: offer.is_advert_mirroring,
		isReserved: offer.is_reserved,
		locality,
		localities: offer.localities && normalizeLocalities(offer.localities),
		manufacturerCb: offer.manufacturer_cb && {
			name: offer.manufacturer_cb.name,
			seoName: offer.manufacturer_cb.seo_name,
			value: offer.manufacturer_cb.value,
		},
		mirroringId: offer.mirroring_id,
		modelCb: offer.model_cb && {
			name: offer.model_cb.name,
			seoName: offer.model_cb.seo_name,
			value: offer.model_cb.value,
		},
		name: offer.name,
		oldId: offer.old_id,
		otherLocalities,
		otherLocalitiesCount: offer.other_localities_count,
		phone: offer.phone,
		premise: offer.premise && normalizeOfferPremiseData(offer.premise),
		preferredOffer: offer.preferred_offer,
		price: offer.price,
		priceByAgreement: offer.price_by_agreement,
		priceOriginal: offer.price_original,
		recommendationData: offer.recommendation_data,
		sautoMoreSeoUrl: offer.sauto_more_seo_url,
		sold: offer.sold,
		seoName: offer.seo_name,
		sortingDate: offer.sorting_date,
		source: offer.source,
		status: offer.status,
		statistics: offer.statistics && { detailView: offer.statistics.detail_view },
		topped: offer.topped,
		user: offer.user ? normalizePublicUserData(offer.user) : undefined,
		validTo: offer.valid_to,
		videos: offer.videos?.map((video) => normalizeOfferVideo(video)),
		videosTotalCount: offer.videos_total_count,
	};
}

export function normalizeOfferData(offer: ApiOfferData, isLabMode?: boolean): OfferData {
	const draftOffer = normalizeDraftOfferData(offer, isLabMode);

	return {
		...draftOffer,
		category: normalizeOfferCategoryData(offer.category),
	} as OfferData;
}

export type WhereSold = 'not_specified' | 'sold_sbazar' | 'sold_other';

function normalizeLocalities(localities: ApiOfferData['localities']) {
	return localities?.map((locality) => ({
		id: locality.id,
		locality: normalizeLocality(locality.locality),
		main: locality.main,
	}));
}

export function isOfferAbleToTop(offer: Partial<OfferData>) {
	return offer.status === 'active' && offer.approvalAdmin !== 'rejected';
}

export function normalizeOfferBuyerProtectionRule(
	rule?: ResponseOfferBuyerProtectionRule,
): BuyerOfferProtectionRule | undefined {
	if (!rule) {
		return undefined;
	}
	return {
		price: rule.price,
		validFromDate: rule.valid_from_date ?? null,
		validToDate: rule.valid_to_date ?? null,
	};
}
