export type ResponseOfferImage = {
	id?: number;
	image_kind?: 0;
	url: string;
};

export type OfferImage = {
	id?: number;
	imageKind?: 0;
	url?: string;
};

export function normalizeOfferImage(image: ResponseOfferImage): OfferImage {
	return {
		id: image.id,
		imageKind: image.image_kind,
		url: image.url,
	};
}
